// Generated by GitHub Copilot
const fs = require("node:fs");
const { GoogleGenerativeAI } = require("@google/generative-ai");

/**
 * Constrói a lista de partes multimodais para o prompt Gemini.
 */
function buildGeminiParts(ask, screenshots) {
  const parts = [
    {
      text: ask
    }
  ];

  screenshots.forEach((item) => {
    if (!fs.existsSync(item.imagePath)) {
      return;
    }

    parts.push({
      inlineData: {
        mimeType: "image/png",
        data: fs.readFileSync(item.imagePath).toString("base64")
      }
    });
  });

  return parts;
}

/**
 * Cria provider Gemini com streaming de texto incremental.
 * Seguranca: a API key permanece apenas no main process.
 */
function createGeminiProvider(options) {
  const logger = options.logger;
  const modelName = options.modelName || process.env.GEMINI_MODEL || "gemini-2.0-flash";

  async function streamAskResponse(input) {
    const genAI = new GoogleGenerativeAI(input.apiKey);
    const model = genAI.getGenerativeModel({ model: modelName });
    const parts = buildGeminiParts(input.ask, input.screenshots);

    logger.info("Starting Gemini streaming request", {
      requestId: input.requestId,
      modelName,
      screenshotCount: input.screenshots.length
    });

    input.onEvent({
      requestId: input.requestId,
      status: "started",
      createdAtIso: new Date().toISOString()
    });

    const streamResult = await model.generateContentStream(parts);
    let fullText = "";

    for await (const chunk of streamResult.stream) {
      const deltaText = chunk.text();
      if (!deltaText) {
        continue;
      }

      fullText += deltaText;
      input.onEvent({
        requestId: input.requestId,
        status: "chunk",
        deltaText,
        fullText,
        createdAtIso: new Date().toISOString()
      });
    }

    input.onEvent({
      requestId: input.requestId,
      status: "completed",
      fullText,
      createdAtIso: new Date().toISOString()
    });

    logger.info("Gemini streaming request completed", {
      requestId: input.requestId,
      outputLength: fullText.length
    });
  }

  return {
    streamAskResponse
  };
}

module.exports = {
  createGeminiProvider
};
